2. MLP Training with Manual Backpropagation
A complete training pipeline: He-initialized multi-layer perceptron, forward pass through ReLU layers, MSE loss, manual chain-rule backward pass, vanilla SGD weight updates, gradient norm tracking, and NaN detection.
// Architecture: [8] → [16, ReLU] → [16, ReLU] → [4, linear]
let scale_in = sqrt(2.0 / float(DIM_IN));     // He initialization

// Weight init
weights = push(weights, Tensor.randn([DIM_IN, DIM_H]) * scale_in);
weights = push(weights, Tensor.randn([DIM_H, DIM_H]) * scale_h);
weights = push(weights, Tensor.randn([DIM_H, DIM_OUT]) * scale_h);

// Synthetic regression target
let X_data = Tensor.randn([BATCH, DIM_IN]);
let teacher = Tensor.randn([DIM_IN, DIM_OUT]) * 0.1;
let Y_data = matmul(X_data, teacher) + Tensor.randn([BATCH, DIM_OUT]) * 0.01;

// Training loop: 100 steps of SGD
let step = 0;
while step &lt; 100 {
    // Forward: Z_l = A_{l-1} @ W_l + b_l, A_l = relu(Z_l)
    let A_prev = X_data;
    let l = 0;
    while l &lt; total_layers {
        let Z = matmul(A_prev, weights[l]) + biases[l];
        if l &lt; total_layers - 1 {
            A_prev = Z * make_relu_mask(Z);   // ReLU via element-wise mask
        } else {
            A_prev = Z;
        }
        l = l + 1;
    }

    // Loss: MSE = mean((pred - target)²)
    let loss = mse_loss(A_prev, Y_data);

    // Backward: chain rule through each layer
    let dA = mse_grad(A_prev, Y_data);
    l = total_layers - 1;
    while l &gt;= 0 {
        let dZ = dA;
        if l &lt; total_layers - 1 { dZ = dA * relu_masks[l]; }
        let dW = matmul(activations[l].transpose(), dZ);
        let db = dZ.sum_axis(0);
        weights[l] = weights[l] - dW * LR;
        biases[l] = biases[l] - db * LR;
        if l &gt; 0 { dA = matmul(dZ, weights[l].transpose()); }
        l = l - 1;
    }
    step = step + 1;
}
