4. Elman RNN — 10,000 Time Steps with Paged KV-Cache
A recurrent neural network processing 10,000 sequential time steps. Uses PagedKvCache to store the full hidden state history with zero per-step allocations — the same memory management strategy used by vLLM for serving large language models.
// Architecture: h_t = gelu(x_t @ W_ih + h_{t-1} @ W_hh + b)
let W_ih = Tensor.from_vec(wih_data, [16, 16]);
let W_hh = Tensor.from_vec(whh_data, [16, 16]);
let h = Tensor.zeros([1, 16]);

// PagedKvCache: pre-allocated block storage for 10,000 hidden states
let state_cache = PagedKvCache.new(10000, 16);

let step = 0;
while step &lt; 10000 {
    let xW = x_token.linear(W_ih, bias);
    let hW = h.linear(W_hh, bias);
    let pre_act = xW + hW;
    h = pre_act.gelu();

    // Zero-allocation append into paged cache
    state_cache.append(h.view_reshape([1, 16]));
    step = step + 1;
}

// Read back any historical hidden state by index
let first_h = state_cache.get_token(0);
let last_h = state_cache.get_token(9999);
