fn init_board() -&gt; Any {
    [4, 2, 3, 5, 6, 3, 2, 4,      // white back rank
     1, 1, 1, 1, 1, 1, 1, 1,      // white pawns
     0, 0, 0, 0, 0, 0, 0, 0, ...  // empty ranks
    -1,-1,-1,-1,-1,-1,-1,-1,       // black pawns
    -4,-2,-3,-5,-6,-3,-2,-4]       // black back rank
}

fn legal_moves(board: Any, side: i64) -&gt; Any {
    let pseudo = generate_pseudo_legal(board, side);
    // Filter: keep only moves where own king isn't in check after
