    let i = 0;
    while i &lt; len(pseudo) {
        let new_board = apply_move(board, pseudo[i], pseudo[i + 1]);
        if !in_check(new_board, side) {
            legal = array_push(legal, pseudo[i]);
            legal = array_push(legal, pseudo[i + 1]);
        }
        i = i + 2;
    }
    legal
}

