Example 1: Numerical Integration
fn trapz(f: fn(f64) -&gt; f64, a: f64, b: f64, n: i64) -&gt; f64 {
    let h = (b - a) / n;
    let mut sum = (f(a) + f(b)) / 2.0;
    for i in 1..n {
        sum = sum + f(a + i * h);
    }
    sum * h
}

fn main() -&gt; f64 {
    let area = trapz(|x: f64| x * x, 0.0, 1.0, 1000);
    print(f"Integral of x^2 from 0 to 1 = {area}");
    area
}


